CustomField.formula:
IF(
AND(
NOT(ISBLANK(Start_Date__c)),
NOT(ISBLANK(TEXT(Estimated_Project_Duration__c)))
),

/* End Date = Start Date + extracted months */
ADDMONTHS(
Start_Date__c,

IF(
/* If duration contains "Year" or "Years" */
CONTAINS(TEXT(Estimated_Project_Duration__c), "Year"),

/* Convert years to months */
12 * VALUE(
LEFT(
TEXT(Estimated_Project_Duration__c),
FIND(" ", TEXT(Estimated_Project_Duration__c)) - 1
)
),

/* Else assume number in months */
VALUE(
LEFT(
TEXT(Estimated_Project_Duration__c),
FIND(" ", TEXT(Estimated_Project_Duration__c)) - 1
)
)
)
),

/* else no value */
NULL
)
